  ('aboriginal-5ff21eeb-moex-00091', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-112-6ed013db', 'sub-aboriginal-5ff21eeb-02', NULL, 'single_choice', '依司法院大法官解釋，有關人民服兵役義務，下列敘述何者錯誤？', '["有關人民服兵役之重要事項，應由立法者斟酌國家安全、社會發展之需要，以法律定之", "後備軍人居住處所遷移，無故不依規定申報者，即處以刑事罰，違憲", "妨害兵役治罪條例，課予後備軍人就居住處所遷移依規定向相關機關為申報之義務，不違憲", "男子服兵役之義務，並無違反人性尊嚴，也無違反平等原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:12+00:00", "source_pdf_sha1": "384194208de1", "answer_pdf_sha1": "a334f7cbe936", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL)
